import play.api._
import play.api.mvc._
import scala.io.Source
import java.nio.file.{Files, Paths}

class FileController extends Controller {
  def serveFile(filename: String) = Action.async { request =>
    val baseDirectoryPath = "/path/to/your/base" // replace with your directory path here
    
    if (request.queryString("..") != null || filename == ".") {
      return Future.successful(BadRequest("Invalid file access attempt")) 
        } else{  
          val fullPath = new java.io.File(baseDirectoryPath + "/"+filename).getCanonicalPath() // get the canonical path of requested files and subdirectories   
           if (new java.io.File(fullPath).exists()) {    
             Source.fromFile(Source.fromFile("/path/to/" + fullPath))  .getLines().map(line => Ok(line)).parsed // serve the file as a stream of lines  
            } else{   
              return Future.successful(NotFound("No such File"))    
             }     
          }      
        }        
}